<script setup lang="ts">
interface Props {
  id?: number
  title: string
  value: string | number
  trend?: string
  trendType?: 'positive' | 'negative' | 'neutral'
  trendSuffix?: string
  sparklineData?: number[]
  color?: string
  secondColor?: string
  withChart?: boolean
}

const props = withDefaults(defineProps<Props>(), {
  trendType: 'neutral'
})

const trendColorClass = computed(() => {
  if (props.trendType === 'positive') return 'text-green-500'
  if (props.trendType === 'negative') return 'text-red-500'
  return 'text-amber-500'
})

const trendColorBackgroundClass = computed(() => {
  if (props.trendType === 'positive') return 'text-green-500 bg-green-500/10'
  if (props.trendType === 'negative') return 'text-red-500 bg-red-500/10'
  return 'text-amber-500 bg-amber-500/10'
})
</script>

